import { useState } from "react";
function App() {
  const [principal, setPrincipal] = useState("");
  const [rate, setRate] = useState("");
  const [time, setTime] = useState("");
  const [emi, setEmi] = useState(null);

  const calculateEmi = async () => {
  const P = parseFloat(principal);
  const annualRate = parseFloat(rate);
  const years = parseFloat(time);
  if (!principal || !rate || !time) {
    alert("Please fill all fields");
    return;
  }

  try {
    const response = await fetch(
      `http://localhost:8080/calculate?principal=${principal}&rate=${rate}&time=${time}`
    );

    const data = await response.json();
    setEmi(data.toFixed(2));

  } catch (error) {
    console.error(error);
    alert("Error connecting to backend");
  }
};

  return (
    <div style={styles.container}>
      <h1>Smart EMI Calculator</h1>

      <input
  type="number"
  placeholder="Loan Amount"
  value={principal}
  style={styles.input}
  onChange={(e) => setPrincipal(e.target.value)}
/>

<br />

<input
  type="number"
  placeholder="Interest Rate (%)"
  value={rate}
  style={styles.input}
  onChange={(e) => setRate(e.target.value)}
/>

<br />

<input
  type="number"
  placeholder="Time (Years)"
  value={time}
  style={styles.input}
  onChange={(e) => setTime(e.target.value)}
/>

<br />

      <button onClick={calculateEmi} style={styles.button}>Calculate EMI</button>
      {emi && <h2>Your EMI: ₹{emi}</h2>}
    </div>
  );
}

const styles = {
  container: {
  textAlign: "center",
  marginTop: "100px",
  backgroundColor: "#f5f5f5",
  height: "100vh",
  },
  input: {
    display: "block",
    margin: "10px auto",
    padding: "10px",
    width: "250px",
    fontSize: "16px",
  },
  button: {
    padding: "10px 20px",
    fontSize: "16px",
    backgroundColor: "#4CAF50",
    color: "white",
    border: "none",
    cursor: "pointer",
  },
};

export default App;
